import React from "react";
import { PublicationsItems } from "./PublicationsItems";

const Publications = () => {
  // Sort publications by year in descending order
  const sortedPublications = PublicationsItems.sort((a, b) => b.year - a.year);

  // Group sorted publications by year
  const groupedPublications = {};
  sortedPublications.forEach((item) => {
    const { year } = item;
    if (!groupedPublications[year]) {
      groupedPublications[year] = [];
    }
    groupedPublications[year].push(item);
  });

  // Define a function to format the list of authors for display.
  const formatAuthors = (authors) => {
    // Check if authors list is empty or undefined, then return null.
    if (!authors || authors.length === 0) return null;

    // Map through the authors list to format each author's name.
    const formattedAuthors = authors.map((author, index) => {
      // If the author's name is "et al.", return it as is without formatting.
      if (author.name === "et al.") {
        return author.name;
      } else if (author.name.includes("Arnott Ferels")) {
        // Bold the name "Arnott Ferels" and add a comma if it's not the last author.
        return index !== authors.length - 1 ? (
          <b>
            {formatName(author.name)}
            {", "}
          </b>
        ) : (
          // Bold "Arnott Ferels" without a comma if it's the last author.
          <b>{formatName(author.name)}</b>
        );
      } else {
        // Format other author names with a comma if they're not the last author.
        return index !== authors.length - 1
          ? `${formatName(author.name)}, `
          : formatName(author.name);
      }
    });

    // Return the formatted list of authors.
    return formattedAuthors;
  };

  const formatName = (name) => {
    const namesArray = name.split(" ");
    const lastName = namesArray.pop(); // Remove and get the last name
    const initials = namesArray.map((name) => name.charAt(0)).join(" ");
    return initials ? `${lastName} ${initials}` : `${lastName}`;
  };

  return (
    <section className="rsm-sec-wrp" title="Publications">
      <h2 className="rsm-h2">Publications</h2>
      <div className="rsm-gd-wrp">
        {Object.entries(groupedPublications)
          .reverse()
          .map(([year, publications], index) => (
            <div key={index} className="rsm-gd">
              <p className="rsm-key">{year}</p>
              <p className="rsm-val">
                {publications.map((item, itemIndex) => (
                  <div
                    key={itemIndex}
                    style={{ marginBottom: "1rem", hyphens: "auto" }}
                  >
                    <>
                      {item.authors && (
                        <>
                          {formatAuthors(item.authors)}
                          &nbsp;
                        </>
                      )}
                    </>

                    <>
                      {item.year && (
                        <>
                          ({item.year}){". "}
                        </>
                      )}
                    </>
                    <>
                      {item.title && (
                        <>
                          {item.title}
                          {item.journal ||
                          item.volume ||
                          item.pages ||
                          item.publisher ||
                          item.event
                            ? ", "
                            : ". "}
                        </>
                      )}
                    </>
                    <>
                      {item.journal && (
                        <>
                          <em> {item.journal}</em>
                          {item.volume ||
                          item.pages ||
                          item.publisher ||
                          item.event
                            ? ", "
                            : ". "}
                        </>
                      )}
                    </>
                    <>
                      {item.volume && (
                        <>
                          {item.volume}
                          {item.pages || item.publisher || item.event
                            ? ", "
                            : ". "}
                        </>
                      )}
                    </>
                    <>
                      {item.pages && (
                        <>
                          {item.pages}
                          {item.publisher || item.event ? ", " : ". "}
                        </>
                      )}
                    </>
                    <>
                      {item.publisher && (
                        <>
                          {item.publisher}
                          {item.event ? ", " : ". "}
                        </>
                      )}
                    </>
                    <>
                      {item.event && (
                        <>
                          <em>{item.event}</em>
                          {". "}
                        </>
                      )}
                    </>
                    <>
                      {item.link && (
                        <>
                          <i>
                            <a
                              href={item.link}
                              title={item.title}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="g-normal-link"
                            >
                              {item.link}
                            </a>
                          </i>
                        </>
                      )}
                    </>

                    <>
                      {item.link_gold && (
                        <>
                          {item.link ? ". " : null}
                          <span className="rsm-gold-btn-link">
                            <a
                              href={item.link_gold}
                              title="Gold Open Access"
                              target="_blank"
                              rel="noopener noreferrer"
                              className="g-btn-link"
                            >
                              Gold OA
                            </a>
                          </span>
                        </>
                      )}
                    </>

                    <>
                      {item.link_green && (
                        <>
                          {item.link ? ". " : null}
                          <span className="rsm-green-btn-link">
                            <a
                              href={item.link_green}
                              title="Green Open Access"
                              target="_blank"
                              rel="noopener noreferrer"
                              className="g-btn-link"
                            >
                              Green OA
                            </a>
                          </span>
                        </>
                      )}
                    </>
                  </div>
                ))}
              </p>
            </div>
          ))}
      </div>
    </section>
  );
};

export default Publications;
